import React, { useState, useEffect } from 'react';
import { scheduleAPI } from '../services/api';
import { toast } from 'react-toastify';
import { FaCalendarAlt, FaClock, FaBuilding, FaUsers } from 'react-icons/fa';
import moment from 'moment';

const ViewSchedule = () => {
  const [schedule, setSchedule] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState({ type: 'all', value: '' });
  const [groupBy, setGroupBy] = useState('date');

  useEffect(() => {
    fetchSchedule();
  }, []);

  const fetchSchedule = async () => {
    try {
      setLoading(true);
      const response = await scheduleAPI.getAll();
      setSchedule(response.data);
    } catch (error) {
      toast.error('Failed to fetch schedule');
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const groupSchedule = () => {
    if (groupBy === 'date') {
      const grouped = {};
      schedule.forEach((exam) => {
        if (!grouped[exam.date]) {
          grouped[exam.date] = [];
        }
        grouped[exam.date].push(exam);
      });
      return Object.entries(grouped).sort((a, b) => a[0].localeCompare(b[0]));
    } else if (groupBy === 'department') {
      const grouped = {};
      schedule.forEach((exam) => {
        if (!grouped[exam.department]) {
          grouped[exam.department] = [];
        }
        grouped[exam.department].push(exam);
      });
      return Object.entries(grouped).sort();
    }
    return [['All', schedule]];
  };

  const exportToCSV = () => {
    if (schedule.length === 0) {
      toast.warning('No schedule to export');
      return;
    }

    const headers = ['Date', 'Time Slot', 'Subject Code', 'Subject Name', 'Hall', 'Department', 'Semester', 'Students'];
    const rows = schedule.map((exam) => [
      exam.date,
      exam.slot,
      exam.subjectCode,
      exam.subjectName,
      exam.hall,
      exam.department,
      exam.semester,
      exam.studentsCount,
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map((row) => row.join(',')),
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `exam-schedule-${moment().format('YYYY-MM-DD')}.csv`;
    a.click();
    toast.success('Schedule exported successfully');
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-16 w-16 border-t-2 border-b-2 border-blue-500"></div>
      </div>
    );
  }

  const groupedSchedule = groupSchedule();

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-lg shadow-md p-6">
        <div className="flex justify-between items-center mb-4">
          <h1 className="text-3xl font-bold text-gray-800">Exam Schedule</h1>
          <div className="flex space-x-2">
            <select
              className="input-field"
              value={groupBy}
              onChange={(e) => setGroupBy(e.target.value)}
            >
              <option value="date">Group by Date</option>
              <option value="department">Group by Department</option>
            </select>
            <button onClick={exportToCSV} className="btn-success">
              Export CSV
            </button>
            <button onClick={fetchSchedule} className="btn-primary">
              Refresh
            </button>
          </div>
        </div>

        {schedule.length === 0 ? (
          <div className="text-center py-12">
            <FaCalendarAlt className="text-gray-300 text-6xl mx-auto mb-4" />
            <p className="text-gray-500 text-lg">No schedule generated yet</p>
            <a href="/generate" className="btn-primary mt-4 inline-block">
              Generate Schedule
            </a>
          </div>
        ) : (
          <div className="space-y-6">
            {groupedSchedule.map(([key, exams]) => (
              <div key={key} className="border rounded-lg overflow-hidden">
                <div className="bg-blue-600 text-white px-6 py-3">
                  <h2 className="text-xl font-semibold">
                    {groupBy === 'date' ? moment(key).format('dddd, MMMM DD, YYYY') : key}
                  </h2>
                  <p className="text-sm opacity-90">{exams.length} exam(s)</p>
                </div>
                <div className="divide-y">
                  {exams.map((exam, idx) => (
                    <div key={idx} className="p-4 hover:bg-gray-50 transition">
                      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        <div>
                          <div className="flex items-center text-gray-600 mb-1">
                            <FaClock className="mr-2" />
                            <span className="font-semibold">{exam.slot}</span>
                          </div>
                          <div className="flex items-center text-gray-600">
                            <FaCalendarAlt className="mr-2" />
                            <span>{moment(exam.date).format('MMM DD, YYYY')}</span>
                          </div>
                        </div>
                        <div className="md:col-span-2">
                          <h3 className="font-bold text-lg text-gray-800">{exam.subjectName}</h3>
                          <p className="text-gray-600">Code: {exam.subjectCode}</p>
                          <p className="text-sm text-gray-500">
                            {exam.department} - Semester {exam.semester}
                          </p>
                        </div>
                        <div className="space-y-2">
                          <div className="flex items-center text-gray-600">
                            <FaBuilding className="mr-2" />
                            <span>Hall: {exam.hall}</span>
                          </div>
                          <div className="flex items-center text-gray-600">
                            <FaUsers className="mr-2" />
                            <span>{exam.studentsCount} students</span>
                          </div>
                          {exam.invigilator && (
                            <p className="text-sm text-gray-500">Invigilator: {exam.invigilator}</p>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default ViewSchedule;
